module four_input_one_output (
    input a,
    input b,
    input c,
    input d,
    output reg out
);

always @(*) begin
    if (a) begin
        out = 1;
    end else if (b) begin
        out = 1;
    end else if (c) begin
        out = 1;
    end else if (d) begin
        out = 1;
    end else begin
        out = 0;
    end
end

  always @(*) begin
    if (1'b0) begin
      out <= ~a & ~b & ~c & ~d;
    end
  end

endmodule
